import { _decorator, Animation, AnimationState, Button, Component, Label, Node, Sprite, SpriteAtlas } from "cc";
import { BuyBonusCell } from "./BuyBonusCell";
import { GameMallInfo, localeStringManager, msgBoxManager, newBottombarManager, soundManager, stateManager } from "db://astarte-framework/Managers";
import { CommonState, Define, tools } from "db://astarte-framework/utilis";
import { SwitchOffKeyDefine } from "db://astarte-framework/License/LicenseSetting";
import Game_Define from "../Game_Define";

const AnimName = {
    Show: "Buy_Feature_Open",
    Hide: "Buy_Feature_Close",
};

interface iGameView
{
    ClickSpin(): void;
}

const { ccclass, property } = _decorator;

@ccclass( "BuyBonus" )
export class BuyBonus extends Component
{
    @property( {
        type: Node,
        tooltip: "介面"
    } )
    private m_viewNode: Node = null;
    @property( {
        type: Animation,
        tooltip: "介面開關動畫"
    } )
    private m_anim: Animation = null;
    @property( {
        type: Node,
        tooltip: "開啟按鈕節點"
    } )
    private m_openBtnNode: Node = null;
    @property( {
        type: Label,
        tooltip: "押注金額"
    } )
    private m_betLabel: Label = null;
    @property( {
        type: BuyBonusCell,
        tooltip: "購買項目"
    } )
    private m_buyBonusCells: BuyBonusCell[] = [];
    @property( {
        type: Sprite,
        tooltip: "標題"
    } )
    private m_titleSprite: Sprite = null;
    @property( {
        type: Sprite,
        tooltip: "押注"
    } )
    private m_betSprite: Sprite = null;

    private m_iGameView: iGameView = null;
    private m_setting: GameMallInfo = null;
    private m_betList: number[] = null;
    private m_betIdx: number = 0;
    private m_bonusType: number = null;
    public get BonusType(): number
    {
        return this.m_bonusType;
    }

    protected start(): void
    {
        this.m_viewNode.active = true;
        let atlas: SpriteAtlas = localeStringManager.GetGameAtlas();
        if ( localeStringManager.CurrLang !== Define.Lang.EN )
        {
            this.m_betSprite.spriteFrame = atlas.getSpriteFrame( "Txt_Buy_Feature_Bet" );
            this.m_titleSprite.spriteFrame = atlas.getSpriteFrame( "Txt_Buy_Feature_Title" );
        }
    }

    Init( info: GameMallInfo, iGameView: iGameView )
    {
        if ( !info || tools.CheckSwitchOff( SwitchOffKeyDefine.ShopingMall ) )
        {
            this.m_viewNode.active = false;
            this.SetBuyBtnVisible( false );
            return;
        }
        this.m_setting = info;
        this.m_iGameView = iGameView;
        this.m_betList = JSON.parse( JSON.stringify( newBottombarManager.GetBetList() ) );
        for ( let i = this.m_betList.length - 1; i >= 0; i-- )
        {
            if ( this.m_betList[ i ] > this.m_setting.MaxBet )
            {
                this.m_betList.splice( i );
            }
            else
            {
                break;
            }
        }
        this.m_betIdx = newBottombarManager.GetNowBetIndex();
        if ( !this.m_betList[ this.m_betIdx ] || this.m_betList[ this.m_betIdx ] > this.m_betList[ this.m_betList.length - 1 ] )
        {
            this.m_betIdx = this.m_betList.length - 1;
        }
        this.SetPrice();
        for ( let i = 0; i < this.m_buyBonusCells.length; i++ )
        {
            let btn: Button = this.m_buyBonusCells[ i ].getComponent( Button );
            btn.node.on( Node.EventType.TOUCH_END, () =>
            {
                soundManager.Play( Define.AudioClips.COMMON_BTN );
                this.m_bonusType = i;
                this.Hide();
                newBottombarManager.SetNowBet( this.m_betList[ this.m_betIdx ] );
                this.m_iGameView.ClickSpin();
            } );
        }
        this.m_viewNode.active = false;
    }

    private SetPrice()
    {
        let bet: number = this.m_betList[ this.m_betIdx ];
        this.m_betLabel.string = `${Define.DollarSymbol}${tools.FormatNumberThousands( bet, tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT )}`;
        for ( let i = 0; i < this.m_buyBonusCells.length; i++ )
        {
            let value = tools.times( bet, this.m_setting.PriceOdd[ i ] );
            this.m_buyBonusCells[ i ].SetPrice( `${Define.DollarSymbol}${tools.FormatNumberThousands( value, tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT )}` );
        }
    }

    SetBuyBtnVisible( visible: boolean )
    {
        this.m_openBtnNode.active = ( !!this.m_setting ) && !tools.CheckSwitchOff( SwitchOffKeyDefine.ShopingMall ) && visible;
    }

    GetBuyBtnVisible()
    {
        return this.m_openBtnNode.active;
    }

    GetBuyBonusBet(): number
    {
        if ( this.m_setting && this.m_bonusType !== null )
        {
            return tools.times( this.m_setting.PriceOdd[ this.m_bonusType ], Game_Define.GetNowBetValue() );
        }
        else
        {
            return tools.strip( Game_Define.GetNowBetValue() );
        }
    }

    CleanInfo()
    {
        this.m_bonusType = null;
    }

    /***********畫面按鈕直接呼叫***********/
    Show()
    {
        if ( stateManager.Current() === CommonState.IDLE )
        {
            let hideAnimState: AnimationState = this.m_anim.getState( AnimName.Hide );
            if ( hideAnimState.isPlaying )
            {
                return;
            }

            soundManager.Play( Define.AudioClips.COMMON_BTN );
            this.m_viewNode.active = true;
            this.m_anim.play( AnimName.Show );
        }
        else
        {
            msgBoxManager.ShowMessageBox( Define.StringKey.FREEWINCASH_PLAYING1 );
        }
    }

    async Hide()
    {
        if ( this.GetBuyBtnVisible() === false )
        {
            this.m_viewNode.active = false;
            return;
        }

        let showAnimState: AnimationState = this.m_anim.getState( AnimName.Show );
        let hideAnimState: AnimationState = this.m_anim.getState( AnimName.Hide );
        if ( showAnimState.isPlaying || hideAnimState.isPlaying )
        {
            return;
        }

        soundManager.Play( Define.AudioClips.COMMON_BTN );
        this.m_anim.play( AnimName.Hide );
        let animState: AnimationState = this.m_anim.getState( AnimName.Hide );
        await Define.Wait( this, animState.duration );
        this.m_viewNode.active = false;
    }

    AddBet()
    {
        if ( this.m_betIdx + 1 > this.m_betList.length - 1 )
        {
            return;
        }
        soundManager.Play( Define.AudioClips.COMMON_BTN );
        this.m_betIdx++;
        this.SetPrice();
    }

    SubBet()
    {
        if ( this.m_betIdx - 1 < 0 )
        {
            return;
        }
        soundManager.Play( Define.AudioClips.COMMON_BTN );
        this.m_betIdx--;
        this.SetPrice();
    }
}

