import { Animation, Component } from "cc";
import { _decorator, Label } from "cc";
import { Define } from "db://astarte-framework/utilis";
import { soundManager } from "db://astarte-framework/Managers";
import Game_Define from "../../Game_Define";

const { ccclass, property } = _decorator;
@ccclass( "FgCounter" )
export class FgCounter extends Component
{
    @property( {
        type: Label
    } )
    private m_label = null;

    @property( {
        type: Animation
    } )
    private m_anim: Animation = null;

    private m_curRound = 0;
    public set CurRound( v: number )
    {
        this.m_curRound = v;
    }

    private m_totoalRound = 0;

    async PlayFire()
    {
        this.m_anim.play( "FX_Num" );
        await Define.Wait( this, 1 );
    }

    /**@ch 加局 */
    AddRound()
    {
        soundManager.Play( Game_Define.AudioClips.FG_Respin );
        this.m_anim.play( "FX_FGRespins" );

        this.m_totoalRound = 3;
        this.CurRound = 3;
        this.SetLabel();
    }

    /**@ch 計算當前局數 */
    CountCurRound()
    {
        this.CurRound = this.m_curRound - 1;
        this.SetLabel();
    }

    /**@ch 設定LABEL */
    SetLabel()
    {
        this.m_label.string = `${this.m_curRound}/${this.m_totoalRound}`;
    }

    /**@ch 設定當前局數 */
    SetCurRound( v: number )
    {
        this.CurRound = v;
        this.SetLabel();
    }

    /**@ch 進入FG設定狀態 */
    EnterFreeGame()
    {
        this.node.active = true;
        this.CurRound = 3;
        this.m_totoalRound = 3;
        this.SetLabel();
    }

    /**@ch 離開FG清理狀態 */
    LeaveFreeGame()
    {
        this.CurRound = 0;
        this.m_totoalRound = 0;
        this.m_label.string = "";
    }
}

