import { Animation, Component } from "cc";
import { _decorator, Label } from "cc";
import { tools } from "db://astarte-framework/utilis";

const { ccclass, property } = _decorator;
@ccclass( "FgCollect" )
export class FgCollect extends Component
{
    @property( {
        type: Label
    } )
    private m_label = null;

    @property( {
        type: Animation
    } )
    private m_anim = null;
    private m_count = 0;

    protected onLoad(): void
    {
        this.m_label.string = this.m_count.toString();
    }

    AddNum( isMaxWin: boolean, value: number, MaxWinValue?: number )
    {
        this.m_count = tools.strip( this.m_count + value );
        if ( isMaxWin && this.m_count > MaxWinValue )
        {
            this.m_count = MaxWinValue;
        }
        this.m_anim.play( "Hit" );

        this.m_label.string = this.m_count.toString();
    }

    ClearAll()
    {
        this.m_count = 0;
        this.m_label.string = this.m_count.toString();
    }
}

