import { _decorator } from "cc";
import GameView from "../GameView";
import { log } from "cc";
import { BaseState, newExtraManager, newBottombarManager } from "db://astarte-framework/Managers";

const { ccclass } = _decorator;

@ccclass( "FeatureShowState" )
export class FeatureShowState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State: FEATURE_SHOW" );
        // autoShowManager.StartAutoShow();

        newBottombarManager.CanPlayFeaturesDemo( true );
        this.m_gameView.IsAutoShowFeatures = true;
        newBottombarManager.SetBarNodeVisiable( true );
        this.m_gameView.SlotReels.node.active = true;
        if ( this.m_gameView.GameIntro )
        {
            this.m_gameView.GameIntro.node.active = false;
        }
        await this.m_gameView.ReelIntro.PlayIntro( 1000 );
        this.m_gameView.ReelIntro.node.active = false;
        this.m_gameView.BuyBonus.SetBuyBtnVisible( true );

        for ( let i = 0; i < this.m_gameView.ScatterCoinSpines.length; ++i )
        {
            this.m_gameView.ScatterCoinSpines[ i ].node.active = true;
        }
        newExtraManager.AutoShowFeatures();
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

