import { _decorator, log } from "cc";
import { stateManager, BaseState, SlotBottomBarState, newBottombarManager, soundManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";

const { ccclass } = _decorator;
@ccclass( "EnterFreeState" )
export class EnterFreeState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State : ENTER_FREE" );

        // change reel speed
        // this.m_gameView.SlotReels.SpinTime = this.m_gameView.SlotReels.SpinTime * Game_Define.FreeSpinSlotSpeedChange;
        // this.m_gameView.SlotReels.SpinIntervalTimes = this.m_gameView.SlotReels.SpinIntervalTimes - Game_Define.FreeSpinSlotColMoreChange;
        // this.m_gameView.CurPlateIndex = this.m_gameView.CurPlateIndex - 1; // 特規
        soundManager.Play( Game_Define.AudioClips.scatter_ring );
        await Define.Wait( this.m_gameView, 3 );

        newBottombarManager.SetEnterFree();
        this.m_gameView.EffectPlate.StopOneLineShow();

        // Show Scatter Win
        // soundManager.Play( Game_Define.AudioClips.Scatter_bell );
        // await Promise.all( [
        //     this.m_gameView.EffectPlate.ShowScatterWin( this.m_gameView.SlotReels.PlateInfo ),
        //     this.m_gameView.AvatarSpine.PlayScatterWin()
        // ] );

        this.m_gameView.IsFreeGame = true;
        this.m_gameView.FgDeclareSpine.SetMultiSkin( this.m_gameView.FgType );
        // this.m_gameView.EffectPlate.ReturnAll();

        // this.m_gameView.EffectPlate.RecoverScatter();
        newBottombarManager.SetBarNodeVisiable( false );
        this.m_gameView.BuyBonus.SetBuyBtnVisible( false );

        soundManager.Pause( this.m_gameView.BgmId );
        soundManager.Play( Game_Define.AudioClips.FG_declare );

        await this.m_gameView.FgDeclareSpine.PlayFgIn();

        if ( !this.m_gameView.FreeBgmId )
        {
            this.m_gameView.FreeBgmId = soundManager.Play( Game_Define.AudioClips.FG_BGM, true );
        }
        else
        {
            soundManager.Resume( this.m_gameView.FreeBgmId );
        }
        newBottombarManager.SetBarNodeVisiable( true );

        // 各遊戲須自己處理自動玩
        if ( newBottombarManager.IsAutoSpin )
        {
            if ( this.m_gameView.AutoplayInfos.isCheckFree )
            {
                newBottombarManager.ShowAutoPlayState( false );
                newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
                this.m_gameView.IsFirstRound = true;
            }
            else
            {
                this.m_gameView.IsFirstRound = false;
            }
        }
        else
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
            this.m_gameView.IsFirstRound = true;
        }

        // this.m_gameView.SinglePlateMgr.SetPlateInfo( RecoverSpinAck.getInstance().ConvertFgPlate( this.m_gameView.RoundInfo.FreePlateSymbol ) );
        // console.error( "MNJHBGTR", RecoverSpinAck.getInstance().ConvertFgPlate( this.m_gameView.RoundInfo.FreePlateSymbol ), this.m_gameView.RoundInfo.FreePlateSymbol );
        // this.m_gameView.SinglePlateMgr.SetFgInPlate( RecoverSpinAck.getInstance().ConvertFgPlate( this.m_gameView.RoundInfo.FreePlateSymbol ) );


        this.m_gameView.SinglePlateMgr.CurCoinNum = 5;

        this.m_gameView.CurScatters = [];

        await this.m_gameView.SinglePlateMgr.ShowFgInScaling();
        if ( this.m_gameView.RoundInfo.BlueData && this.m_gameView.RoundInfo.BlueData[ 0 ] )
        {
            this.m_gameView.SinglePlateMgr.CurCoinNum = this.m_gameView.SinglePlateMgr.CurCoinNum + 1;
            await this.m_gameView.EffectPlate.PlayTigerEffect( this.m_gameView.RoundInfo.BlueData );
        }
        if ( this.m_gameView.RoundInfo.RedData && this.m_gameView.RoundInfo.RedData[ 0 ] )
        {
            this.m_gameView.SinglePlateMgr.CurCoinNum = this.m_gameView.SinglePlateMgr.CurCoinNum + 1;
            await this.m_gameView.EffectPlate.PlayLoongEffect( this.m_gameView.RoundInfo.RedData );
        }
        if ( this.m_gameView.RoundInfo.GreenData && this.m_gameView.RoundInfo.GreenData[ 0 ] )
        {
            this.m_gameView.SinglePlateMgr.CurCoinNum = this.m_gameView.SinglePlateMgr.CurCoinNum + 1;
            await this.m_gameView.EffectPlate.PlayKoiEffect( this.m_gameView.RoundInfo.GreenData );
        }

        // NextState
        stateManager.NextState( Game_Define.GameState.ROUND_END );
    }

    public OnProcess() 
    {

    }

    public OnLeave() 
    {

    }
}

