        this.LeaveFreeSetting();
        // }
    }

    async LeaveFreeSetting()
    {
        this.m_gameView.FgCollect.ClearAll();

        soundManager.Pause( this.m_gameView.FreeBgmId );

        this.m_gameView.FgCollect.node.active = false;
        newBottombarManager.SetBarNodeVisiable( false );
        await this.m_gameView.FgComplimentSpine.PlayFgCompliment( this.m_gameView.SpinAck.FreeTotalWin );
        newBottombarManager.SetBarNodeVisiable( true );
        this.m_gameView.BuyBonus.SetBuyBtnVisible( true );

        newBottombarManager.SetLeaveFree();
        newBottombarManager.LockBetEnable( true );

        soundManager.Resume( this.m_gameView.BgmId );

        this.m_gameView.FgCounter.LeaveFreeGame();

        // 切換轉輪
        this.m_gameView.SlotReels.node.active = true;
        this.m_gameView.SinglePlateMgr.node.active = false;

        // 特色描述
        if ( !tools.CheckSwitchOff( SwitchOffKeyDefine.CloseManual ) )
        {
            this.m_gameView.Manual.node.active = true;
        }

        // 播放MainGame BGM
        soundManager.Resume( this.m_gameView.BgmId );
        // 一般離開時要做的狀態改變，因為須配合結算動畫，改寫在FGOutManager裡面
        // this.FGOutSetting();
        this.m_gameView.IsFreeGame = false;
        for ( let i = 0; i < this.m_gameView.ScatterCoinSpines.length; ++i )
        {
            this.m_gameView.ScatterCoinSpines[ i ].ChangeScatterLevel( this.m_gameView.CrackLevels[ i ] );
            // this.m_gameView.ScatterCoinSpines[ i ].PlayIdle();
            // this.m_gameView.ScatterCoinSpines[ i ].ResetScatterSkin();
        }

        stateManager.NextState( Game_Define.GameState.ROUND_END );
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

