/** 一整條的size大小 */
private m_symbolSize: Size = null;
private m_viewSize: Size = null;
private m_gameView: GameView = null;

onLoad()
{

}

Init( gameView: GameView )
{
    this.m_gameView = gameView;

    // Size 大小設定
    this.m_viewSize = this.node.getComponent( UITransform ).contentSize; //3.6.2
    this.m_symbolSize = new Size(
        ( this.m_viewSize.width - Game_Define.SeparateLineWidth * ( Game_Define.COL - 1 ) ) / Game_Define.COL,
        this.m_viewSize.height / Game_Define.ROW
    );

    this.SetSingleReelSpinOrder();

    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        let nodeArr = [];
        let isLockedArr = [];
        let countCoin = [];

        let x = this.m_symbolSize.width * ( col + 0.5 )
            - this.m_viewSize.width / 2
            + Game_Define.SeparateLineWidth * col;

        for ( let row = 0; row < Game_Define.ROW; ++row )
        {
            let SingleSingleReel = instantiate( this.m_SingleSingleReel );
            let idx = col * 10 + row;
            SingleSingleReel.name = ( idx ).toString();
            let cellInfo = new FgCellInfo();
            cellInfo.Symbol = Game_Define.Symbol.Coin;
            SingleSingleReel.getComponent( SingleSlotReel ).Init( this.m_gameView, col, row, cellInfo );

            // 把位置放好
            let y = 0;
            SingleSingleReel.setPosition( x, y );
            this.m_reelMask[ row ].addChild( SingleSingleReel );
            nodeArr.push( SingleSingleReel );
            isLockedArr.push( false );

            countCoin.push( 0 );
        }
        this.m_singleReelNodes.push( nodeArr );
        this.m_isLocked.push( isLockedArr );
        this.m_countCoin.push( countCoin );
    }
}

/**@ch 檢查出金幣數量 */
CheckCoinNumbers()
{
    let CoinNumbers = 0;
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        for ( let row = 0; row < Game_Define.ROW; ++row )
        {
            if ( this.m_plateInfo[ col ].Col[ row ].Symbol >= Game_Define.Symbol.Scatter_Tiger
                && this.m_plateInfo[ col ].Col[ row ].Symbol <= Game_Define.Symbol.Coin_Green )
            {
                this.IsLocked[ col ][ row ] = true;
                ++CoinNumbers;
            }
        }
    }
    this.m_curCoinNum = CoinNumbers;
}

/**@ch FG in 新金幣放大特效 */
async ShowFgInScaling()
{
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        for ( let row = 0; row < Game_Define.ROW; ++row )
        {
            if ( this.m_plateInfo[ col ].Col[ row ].Symbol === Game_Define.Symbol.Coin )
            {
                // info設定
                let info = new FgCellInfo();
                info.Symbol = this.m_plateInfo[ col ].Col[ row ].Symbol;
                info.Value = this.m_plateInfo[ col ].Col[ row ].Number;
                info.JpType = this.m_plateInfo[ col ].Col[ row ].JPState;

                let coinNode = this.m_gameView.EffectPlate.SetEffectInfo( info, col, row );

                soundManager.Play( Game_Define.AudioClips.scatter_yellow );
                // FG 進場表演
                await this.m_gameView.EffectPlate.NodeScalingEffect(
                    coinNode,
                    Game_Define.InitSize,
                    Game_Define.EndSize,
                    0.5
                );
            }
        }
    }
}

SetFgInPlateInfo( content: protocol.tctProto.ICColumn[] )
{
    this.PlateInfo = RecoverSpinAck.getInstance().ConvertFgPlate( content );
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        for ( let row = 0; row < Game_Define.ROW; ++row )
        {
            if ( this.m_isLocked[ col ][ row ] )
            {
                continue;
            }

            let info = new FgCellInfo();
            info.Symbol = this.m_plateInfo[ col ].Col[ row ].Symbol;
            info.Value = this.m_plateInfo[ col ].Col[ row ].Number;
            info.JpType = this.m_plateInfo[ col ].Col[ row ].JPState;
            info.JpMult = this.m_plateInfo[ col ].Col[ row ].JPMult;

            this.m_singleReelNodes[ col ][ row ]
                .getComponent( SingleSlotReel )
                .SetSymbolInfos(
                    info,
                    this.m_SingleReelSpinTimes[ col ][ row ]
                );
        }
    }
}

SetPlateInfo( content: protocol.tctProto.ICColumn[] )
{
    this.PlateInfo = RecoverSpinAck.getInstance().ConvertFgPlate( content );
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        for ( let row = 0; row < Game_Define.ROW; ++row )
        {
            if ( this.m_isLocked[ col ][ row ] )
            {
                continue;
            }

            let info = new FgCellInfo();
            info.Symbol = tools.strip( this.m_plateInfo[ col ].Col[ row ].Symbol );
            info.Value = tools.strip( this.m_plateInfo[ col ].Col[ row ].Number );
            info.JpType = this.m_plateInfo[ col ].Col[ row ].JPState;
            info.JpMult = this.m_plateInfo[ col ].Col[ row ].JPMult;

            let reelSpinTimesInfos =
                //  this.IsClickStopBtn ? this.m_fastSingleReelSpinTimes[ col ][ row ] :
                this.m_SingleReelSpinTimes[ col ][ row ];

            this.m_singleReelNodes[ col ][ row ]
                .getComponent( SingleSlotReel )
                .SetSymbolInfos(
                    info,
                    reelSpinTimesInfos
                );
        }
    }
}

/**@ch 包含設定symbol Sprite */
SetPlateSymbol( content: protocol.tctProto.ICColumn[] )
{
    this.PlateInfo = RecoverSpinAck.getInstance().ConvertFgPlate( content );
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        for ( let row = 0; row < Game_Define.ROW; ++row )
        {
            if ( this.m_isLocked[ col ][ row ] )
            {
                continue;
            }

            let info = new FgCellInfo();
            info.Symbol = tools.strip( this.m_plateInfo[ col ].Col[ row ].Symbol );
            info.Value = tools.strip( this.m_plateInfo[ col ].Col[ row ].Number );
            info.JpType = this.m_plateInfo[ col ].Col[ row ].JPState;
            info.JpMult = this.m_plateInfo[ col ].Col[ row ].JPMult;

            let reelSpinTimesInfos =
                //  this.IsClickStopBtn ? this.m_fastSingleReelSpinTimes[ col ][ row ] :
                this.m_SingleReelSpinTimes[ col ][ row ];

            this.m_singleReelNodes[ col ][ row ]
                .getComponent( SingleSlotReel )
                .SetSymbolInfos(
                    info,
                    reelSpinTimesInfos
                );

            this.m_singleReelNodes[ col ][ row ]
                .getComponent( SingleSlotReel )
                .AllColumns[ Game_Define.MIDDLE_PLATE_INDEX ]
                .ChangeSymbol( info );

            for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
            {
                this.m_singleReelNodes[ col ][ row ]
                    .getComponent( SingleSlotReel )
                    .AllColumns[ plate ]
                    .ShowSymbol();
            }
        }
    }
}

/**@ch FG進場時的轉換設定*/
SetCell( col: number, row: number, info: FgCellInfo )
{
    this.m_singleReelNodes[ col ][ row ]
        .getComponent( SingleSlotReel )
        .AllColumns[ Game_Define.MIDDLE_PLATE_INDEX ]
        .ChangeSymbol( info );
}

/**@ch 取symbol種類 */
GetSymbolByIndex( col: number, row: number )
{
    return this.m_singleReelNodes[ col ][ row ];
}

/**@ch 設定停輪順序，左上至右下 */
SetSingleReelSpinOrder()
{
    for ( let j = 0; j < Game_Define.ROW; j++ )
    {
        for ( let i = 0; i < Game_Define.COL; i++ )
        {
            this.m_SingleReelSpinTimes[ i ][ j ] = i + j + 1;
        }
    }
}

SetSymbolDark( i: number, j: number, toDark: boolean = true )
{
    this.m_singleReelNodes[ i ][ j ].getComponent( SingleSlotReel ).SetSymbolDark( toDark );
}

/** @ch 更新停輪相關時間 @en Update stopTime, reelStopTime, reelPreTime and ClickStopBtn*/
ClickStopBtn()
{
    let hasScatter = false;
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        for ( let row = 0; row < Game_Define.ROW; ++row )
        {
            if ( this.m_isLocked[ col ][ row ] )
            {
                continue;
            }

            if ( this.m_plateInfo[ col ].Col[ row ].Symbol < Game_Define.Symbol.Scatter_Tiger
                || this.m_plateInfo[ col ].Col[ row ].Symbol === Game_Define.Symbol.MAX )
            {
                hasScatter = true;
            }

            this.m_singleReelNodes[ col ][ row ].getComponent( SingleSlotReel ).ClickStopBtn();
        }
    }
    if ( hasScatter ) soundManager.Play( Game_Define.AudioClips.scatter_stop );
