import { _decorator } from "cc";
import { log } from "cc";
import GameView from "../GameView";
import { BaseState, stateManager } from "db://astarte-framework/Managers";
import Game_Define from "../Game_Define";

const { ccclass } = _decorator;

@ccclass( "CheckState" )
export class CheckState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public OnEnter()
    {
        log( "OnEnter state : CHECK_STATE" );

        // console.error(
        //     "Check State Info",
        //     this.m_gameView.IsFreeGame,
        //     this.m_gameView.SinglePlateMgr.CurCoinNum,
        //     this.m_gameView.RoundInfo.FreeRemainRound,
        //     this.m_gameView.SinglePlateMgr.HasNewCoin
        // );

        if ( this.m_gameView.IsGoingToFree )
        {
            this.m_gameView.IsGoingToFree = false;
            stateManager.NextState( Game_Define.GameState.ENTER_FREE );
        }
        else if (
            this.m_gameView.IsFreeGame
            && (
                this.m_gameView.RoundInfo.AwardTypeFlag & 0x80
                // this.m_gameView.SinglePlateMgr.CurCoinNum === 15
                // || (
                //     this.m_gameView.RoundInfo.FreeRemainRound
                //     && this.m_gameView.CurPlateIndex + 1 === this.m_gameView.SpinAck.RoundQueue.length )
            )
        )
        {
            stateManager.NextState( Game_Define.GameState.FULL_REWARD );
        }
        else if (
            this.m_gameView.IsFreeGame
            && (
                this.m_gameView.RoundInfo.FreeRemainRound === 0
                || this.m_gameView.RoundInfo.FreeRemainRound === undefined
            )
        )
        {
            stateManager.NextState( Game_Define.GameState.LEAVE_FREE );
        }
        else if (
            this.m_gameView.IsFreeGame
            && this.m_gameView.SinglePlateMgr.HasNewCoin
        )
        {
            stateManager.NextState( Game_Define.GameState.ADD_FREE );
        }
        else
        {
            stateManager.NextState( Game_Define.GameState.ROUND_END );
        }
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

