    if ( isFast )
    {
        await this.m_gameView.EffectPlate.FgStop( this.m_symbolInfo, this.m_col, this.m_row );
    }
    else
    {
        await this.m_gameView.EffectPlate.FgStop( this.m_symbolInfo, this.m_col, this.m_row );
    }
}

/**@ch 停輪相關音效 */
PlayReelSound()
{
    if ( this.m_isClickStopBtn )
    {
        return;
    }

    if (
        this.m_symbolInfo.Symbol >= Game_Define.Symbol.Scatter_Tiger
        && this.m_symbolInfo.Symbol <= Game_Define.Symbol.Coin_Green
    )
    {
        soundManager.Play( Game_Define.AudioClips.scatter_stop );
    }
    else soundManager.Play( Game_Define.AudioClips.reel_stop );
}

/** @ch 更新停輪相關時間 @en Update stopTime, reelStopTime, reelPreTime and ClickStopBtn*/
ClickStopBtn()
{
    if ( this.m_stopTime === 0 )
    {
        return;
    }

    this.m_isClickStopBtn = true;
    let timesOfSpin = Math.ceil( this.Time / this.m_spinTime );
    timesOfSpin = timesOfSpin > 0 ? timesOfSpin : 1;
    let reelPreTime = timesOfSpin * this.m_spinTime;
    let reelStopTime = tools.strip( reelPreTime + this.m_spinTime );
    if ( this.m_reelStopTime > reelStopTime )
    {
        this.m_reelStopTime = reelStopTime;
        this.m_reelPreTime = reelPreTime;
    }

    // let stopTime = reelStopTime
    //     + this.m_spinDelayTime
    //     + this.m_spinBufferTime01
    //     + this.m_spinBufferTime02;

    // 轉輪節奏模組：三幣瑞龍
    let stopTime = tempoSetting.TempoSetting.TripleCoinTreasure.SPEED_UP_STOP_TIME( 0, this.m_time );

    if ( this.m_stopTime > stopTime )
    {
        this.m_stopTime = tools.strip( stopTime );
    }
}

Spin( dt )
{
    this.Time = tools.strip( this.Time + dt );
    if ( this.m_isStop )
    {
        return;
    }

    this.SpinAll();
    if ( this.m_stopTime === 0 || this.Time < this.m_stopTime )
    {
        return;
    }

    // 該停輪了
    this.m_isStop = true;
    if ( this.m_nearWinEndFunc )
    {
        this.m_nearWinEndFunc();
        this.m_nearWinEndFunc = this.m_nearWinStartFunc = null;
    }
    if ( this.IsNearWin )
    {
        this.StopNearWinSound();
    }

    if ( this.m_reelSoundId )
    {
        soundManager.Stop( this.m_reelSoundId );
        this.m_reelSoundId = null;
    }
}

/**@ch 停止播放NearWin音效 */
StopNearWinSound()
{
    for ( let i = 0; i < this.m_nearWinSoundId.length; ++i )
    {
        soundManager.Stop( this.m_nearWinSoundId[ i ] );
        this.m_nearWinSoundId[ i ] = -1;
    }
}

/**@ch 旋轉上、中、下所有輪帶*/
SpinAll()
{
    // // NearWin
    // if ( this.IsNearWin() )
    // {
    //     this.NearWinEffect();
    // }

    if ( this.m_gameView.SinglePlateMgr.CurCoinNum === Game_Define.FG_NEARWIN_NUM && !this.m_hasPlayNearWin )
    {
        soundManager.Play( Game_Define.AudioClips.FG_near );
        this.m_hasPlayNearWin = true;
        this.m_stopTime = this.m_stopTime + this.m_nearWinMoreSpin * this.m_spinTime;
        this.m_reelPreTime = this.m_reelPreTime + this.m_nearWinMoreSpin * this.m_spinTime;
        this.m_reelStopTime = this.m_reelStopTime + this.m_nearWinMoreSpin * this.m_spinTime;
        this.m_gameView.EffectPlate.PlayNearWin( this.m_col, this.m_row );
    }

    let moveLength = this.CalculateSpinPos( this.IsNearWin() );

    for ( let plate = 0; plate < SHOW_COLUMNS; ++plate ) // 上中下總共三條
    {
        this.Spin_RealSpinMultiple( this.m_allColumns[ plate ], plate, moveLength );
    }
}

/**@ch 根據時間，做出對應表演，座標與一般直角座標系相同 */
Spin_RealSpinMultiple( target: SingleCell, lowMiddleUp: number, moveLength: number )
{
    let curTime = this.Time;
    let reelStopTime = this.m_reelStopTime;
    // let reelPreTime = this.m_reelPreTime;
    let riseTime = this.m_riseTime;

    let x = this.m_reelXPos;
    let y = this.m_reelYPos[ lowMiddleUp ];

    if (
        lowMiddleUp === Game_Define.MIDDLE_PLATE_INDEX
        && curTime > reelStopTime + riseTime + this.m_spinBufferTime01 + this.m_spinBufferTime02
    )
    {
        y = this.m_reelYPos[ lowMiddleUp ];
        target.SetPosition( v3( x, y ) );
    }

    // 抬起續力表演
    if ( curTime < this.m_riseTime )
    {
        //     return;
        // }
        // else if ( curTime < this.m_riseTime * ( 1 ) )
        // {
        //     let moveLength = ( ( curTime - this.m_riseTime ) / this.m_riseTime ) * this.m_upLength;
        //     target.SetPosition( v3( x, y + moveLength ) );
        // }
        // else if ( curTime < riseTime )
        // {
        target.SetPosition( v3( x, y + this.m_upLength ) );
    }
    // 轉動表演
    else if ( reelStopTime === null || curTime < reelStopTime + riseTime )
    {
        let finalMoveLength = this.CheckMoveLength( moveLength, this.m_comparePos[ lowMiddleUp ], target, lowMiddleUp );
        target.SetPosition( v3( x, y - finalMoveLength ) );
    }
    // 準備要停了
    else if ( curTime < reelStopTime + riseTime + this.m_spinBufferTime01 )
    {
        let moveLength = ( ( curTime - reelStopTime - riseTime ) / this.m_spinBufferTime01 ) * this.m_downLength;
        target.SetPosition( v3( x, y - moveLength ) );
        this.CheckChangeToFinalSymbol( target, lowMiddleUp, true );
        // this.CheckPlayStopSoundAndEffect();
        this.ShowStopSymbolEffect( this.m_isClickStopBtn );
    }
    else if ( curTime < reelStopTime + riseTime + this.m_spinBufferTime01 + this.m_spinBufferTime02 )
    {
        let moveLength = ( ( curTime - reelStopTime - riseTime - this.m_spinBufferTime01 ) / this.m_spinBufferTime02 ) * this.m_downLength;
        target.SetPosition( v3( x, y - this.m_downLength + moveLength ) );
        this.CheckChangeToFinalSymbol( target, lowMiddleUp, true );
    }
    else
    {
        this.CheckChangeToFinalSymbol( target, lowMiddleUp, true );
        target.SetPosition( v3( x, y ) );
        this.CheckPlayStopSoundAndEffect();
        this.ShowStopSymbolEffect( this.m_isClickStopBtn );
    }
}

/**@ch 確認是不是可以換Symbol了，順便拉到上面*/
CheckMoveLength( moveLength: number, comapreLength: number, target: SingleCell, upMiddleLow: number )
{
    if ( moveLength < comapreLength )
    {
        return moveLength;
    }

    if (
        this.m_isNotChangeSymbolThisRound[ upMiddleLow ]
        && moveLength - comapreLength < this.m_viewSize.height // 只在Plate拉到最上面時換一次(成為最上面的plate時)
    )
    {
        this.ChangeSymbol( target, this.m_isClickStopBtn, upMiddleLow );
        this.m_isNotChangeSymbolThisRound[ upMiddleLow ] = false;
    }
    else
    {
        this.m_isNotChangeSymbolThisRound[ upMiddleLow ] = true;
    }
    return moveLength - this.m_totalLength;
}

/**@ch 幫單個column換Symbol */
ChangeSymbol( node: SingleCell, isStop: boolean, upMiddleLow: number )
{
    let index = Number( node.Name );
    let reelPreTime = this.m_reelPreTime;
    let riseTime = this.m_riseTime * this.m_viewSize.height * SHOW_COLUMNS;

    if ( isStop )
    {
        // 中間輪帶
        if ( upMiddleLow === 1 )
        {
            node.SetInfo( this.m_symbolInfo );
        }
        else
        {
            let symbolInfos = this.RandomSymbolInfo();
            node.SetInfo( symbolInfos );
        }
    }
    else
    {
        if ( index >= 0
            && ( ( reelPreTime !== null && this.Time >= reelPreTime )
                || ( Math.abs( this.Time - ( reelPreTime + riseTime ) ) < this.m_spinTime ) )
        )
        {
            node.SetInfo( this.m_symbolInfo );
        }
        else
        {
            let symbolInfos = this.RandomSymbolInfo();
            node.SetInfo( symbolInfos );
        }
    }
}

ClearAll()
{
    this.m_allColumns[ Game_Define.MIDDLE_PLATE_INDEX ].ClearAll();
}

/**@ch 最後一道防線 */
CheckChangeToFinalSymbol( node: SingleCell, upMiddleLow: number, isStop = false )
{
    if ( !this.m_isChangeToFinalSymbol[ upMiddleLow ] )
    {
        this.ChangeSymbol( node, isStop, upMiddleLow );
        this.m_isChangeToFinalSymbol[ upMiddleLow ] = true;
    }
}

/**@ch 確認停輪效果(亞瑟王音效與動態分開) */
CheckPlayStopSoundAndEffect()
{
    if ( !this.m_isPlayStopSound )
    {
        this.m_isPlayStopSound = true;
        this.PlayReelSound();
    }
}

/**@ch 設置當局盤面資料，以及停輪時間等相關設定 */
SetSymbolInfos( info: FgCellInfo, SpinRounds: number )
{
    this.m_symbolInfo = info;

    let riseTime = this.m_riseTime;
    let timesOfSpin = Math.ceil( ( this.Time - riseTime ) / this.m_spinTime );
    timesOfSpin = timesOfSpin !== 0 ? timesOfSpin : 1;

    this.m_reelPreTime =
        this.m_spinTime * ( SpinRounds - 1 + timesOfSpin )
        + this.m_spinDelayTime
        + riseTime;

    // 盤面spin時間不能加上有的沒的，那些有的沒的要給reelSpinMultiple做判斷
    this.m_reelStopTime =
        this.m_spinTime * ( SpinRounds + timesOfSpin )
        + this.m_spinDelayTime
        + riseTime;

    this.m_stopTime =
        this.m_reelStopTime
        + this.m_spinBufferTime01
        + this.m_spinBufferTime02;

    // if ( this.m_symbolInfo.Symbol >= Game_Define.Symbol.Scatter_Tiger
    //     && this.m_symbolInfo.Symbol < Game_Define.Symbol.Coin )
    // {
    //     this.IsScatter = true;
    // }

    if (
        info.Symbol > Game_Define.Symbol.WILD
        && info.Symbol <= Game_Define.Symbol.Coin_Green
    )
    {
        this.IsCoin = true;
        if ( info.Symbol < Game_Define.Symbol.Coin )
        {
            this.IsScatter = true;
        }
    }

    // if ( this.IsCoin )
    // {
    //     this.m_gameView.EffectPlate.SpawnCoin( this.m_symbolInfo, this.m_col, this.m_row );
    // }
}

IsNearWin(): boolean
{
    return this.m_nearWinNowCol !== -1
        && this.m_nearWinNowCol !== Game_Define.COL
        && !this.m_gameView.IsHardStop;
    // && !this.m_gameView.IsManualHardStop;
    // && !this.m_gameView.IsFreeGame;    // 阿里巴巴  FG裡面也要做nearwin
}

