            this.m_nearWinStartFunc( this.m_nearWinNowCol );
            this.m_nearWinNowCol = this.m_nearWinNowCol + 1;
            if ( this.m_nearWinSoundId[ this.m_nearWinNowCol ] < 0 )
            {
                // this.m_nearWinSoundId[ this.m_nearWinNowCol ] = soundManager.Play(
                //     Game_Define.AudioClips.NearWin,
                //     false,
                //     null,
                //     1
                // );
            }
        }
        else
        {
            this.m_nearWinEndFunc();
        }
    }
}

