SetSymbolDark( isDark: boolean )
{
    for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
    {
        this.m_allColumns[ plate ].SetSymbolDark( isDark );
    }
}

/**@ch 檢查此Column已經是否停輪 */
CheckColIsStop()
{
    return this.Time >= this.m_reelStopTime;
}

